**File:** `/tmp/p15-test-iFHIHD/app.js`
**Date:** 2026-04-26
**Severity Legend:** 🔴 Critical | 🟠 High | 🟡 Medium | 🔵 Low | ℹ️ Informational

---

## Summary

The application is a minimal Express.js server with two routes (`/health`, `/users`). While small, it has **multiple significant security gaps** that would be critical to address before any production use. Issues span authentication, information exposure, missing security headers, rate limiting, and error handling.

---

## Findings

---

### 🔴 1. Unauthenticated PII Exposure — `/users` Endpoint
**OWASP A01:2021 – Broken Access Control | A02:2021 – Cryptographic/Data Failures**

The `/users` route returns names and email addresses with **zero authentication or authorization**. Any unauthenticated caller can enumerate all users.

```js
// ❌ Current — anyone can call this
app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    ...
  ]);
});
```

**Recommendation:** Add an authentication middleware (e.g., JWT or session-based). At minimum:

```js
// ✅ Example using a JWT bearer-token middleware
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader?.split(' ')[1]; // "Bearer <token>"
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Forbidden' });
    req.user = user;
    next();
  });
};

app.get('/users', authenticateToken, (req, res) => { ... });
```

Also consider returning only fields the caller is authorized to see (field-level access control).

---

### 🔴 2. No Security Headers
**OWASP A05:2021 – Security Misconfiguration**

Express ships with no security-hardening headers by default. Without them, the app is vulnerable to clickjacking, MIME sniffing, cross-site scripting via injected content, and information leakage (`X-Powered-By: Express`).

```js
// ❌ Current — no helmet, X-Powered-By still advertised
const app = express();
```

**Recommendation:** Add [`helmet`](https://helmetjs.github.io/):

```js
// ✅
const helmet = require('helmet');
app.use(helmet()); // Sets: X-Content-Type-Options, X-Frame-Options,
                   // Strict-Transport-Security, Content-Security-Policy,
                   // and removes X-Powered-By, among others.
```

---

### 🟠 3. No Rate Limiting / DoS Protection
**OWASP A04:2021 – Insecure Design**

There is no rate limiting on any endpoint. An attacker can hammer `/users` (or any future endpoint) with unlimited requests, enabling enumeration, denial-of-service, or brute-force against future auth endpoints.

```js
// ❌ Current — unbounded request rate
app.get('/users', ...)
```

**Recommendation:** Use [`express-rate-limit`](https://github.com/express-rate-limit/express-rate-limit):

```js
// ✅
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use(limiter); // apply globally, or per-route
```

---

### 🟠 4. Hardcoded Port — No Environment Variable
**OWASP A05:2021 – Security Misconfiguration**

The port `3000` is hardcoded. In production deployments this prevents port assignment by the orchestration layer and can expose internal services on unintended ports.

```js
// ❌ Current
app.listen(3000, () => { ... });
```

**Recommendation:**

```js
// ✅
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

---

### 🟠 5. No Global Error Handler — Potential Stack Trace Leakage
**OWASP A05:2021 – Security Misconfiguration**

Express's default error handler sends raw stack traces in development mode and can leak them in production if `NODE_ENV` is not set correctly. There is no custom error handler in this file.

```js
// ❌ Current — default Express error propagation
// A future middleware throwing an error would expose internals
```

**Recommendation:** Add an error-handling middleware at the end of the middleware chain:

```js
// ✅ — place AFTER all routes
app.use((err, req, res, next) => {
  const statusCode = err.status || 500;
  // Log internally with full details
  console.error({ message: err.message, stack: err.stack, path: req.path });
  // Respond with sanitized message only
  res.status(statusCode).json({
    error: process.env.NODE_ENV === 'production'
      ? 'An unexpected error occurred.'
      : err.message,
  });
});
```

---

### 🟡 6. No CORS Policy Defined
**OWASP A05:2021 – Security Misconfiguration**

No CORS configuration is set. Depending on your deployment context and whether this API is consumed by a browser, this either allows no cross-origin requests (default) or can be accidentally opened wide if middleware is added later without restriction.

**Recommendation:** Be explicit with an allowlist:

```js
// ✅
const cors = require('cors');

app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? [],
  methods: ['GET'],       // restrict to only what's needed
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

---

### 🟡 7. Timestamp in `/health` — Server Information Disclosure
**OWASP A05:2021 – Security Misconfiguration**

The `/health` endpoint returns `new Date().toISOString()`. While low severity on its own, server-side timestamps can be used by attackers to:
- Infer server clock skew for timing attacks
- Confirm the service is live for reconnaissance

```js
// ❌ Current
res.json({ status: 'ok', timestamp: new Date().toISOString() });
```

**Recommendation:** Return only what consumers genuinely need:

```js
// ✅ — omit timestamp or gate it behind auth
res.json({ status: 'ok' });
```

---

### 🟡 8. No Request Logging / Audit Trail
**OWASP A09:2021 – Security Logging and Monitoring Failures**

There is no request logging. Security events (auth failures, unexpected routes, etc.) are invisible, making incident detection and forensics impossible.

**Recommendation:** Use [`morgan`](https://github.com/expressjs/morgan) or a structured logger:

```js
// ✅
const morgan = require('morgan');
app.use(morgan('combined')); // Apache-style logs; use 'tiny' or JSON for structured logging
```

For production, pair this with a log aggregation service (e.g., Datadog, CloudWatch, Splunk).

---

### 🔵 9. No Body Size Limit on Future POST Routes
**OWASP A03:2021 – Injection (precautionary)**

There is no `express.json()` or `express.urlencoded()` with a `limit` configured. If POST routes are added in the future, omitting a size limit allows large-payload DoS attacks.

**Recommendation:** Add this proactively:

```js
// ✅ — add before route definitions
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));
```

---

### ℹ️ 10. No Input Validation on Query Parameters
**OWASP A03:2021 – Injection (future risk)**

Currently no routes accept user-supplied input, so there is no immediate injection risk. However, as soon as query parameters, path parameters, or request bodies are introduced (e.g., `GET /users?id=…`), there will be no validation layer in place.

**Recommendation:** Adopt [`zod`](https://github.com/colinhacks/zod) or [`joi`](https://github.com/hapijs/joi) now and validate all inputs at route entry points before any business logic or database access:

```js
// ✅ Example with zod for a future /users/:id route
const { z } = require('zod');

const userIdSchema = z.object({
  id: z.coerce.number().int().positive(),
});

app.get('/users/:id', authenticateToken, (req, res) => {
  const result = userIdSchema.safeParse(req.params);
  if (!result.success) {
    return res.status(400).json({ error: 'Invalid user ID', details: result.error.issues });
  }
  const { id } = result.data;
  // safe to use id here
});
```

---

## Prioritized Remediation Checklist

| Priority | Finding | Action |
|---|---|---|
| 🔴 | Unauthenticated `/users` endpoint exposes PII | Add JWT/session auth middleware |
| 🔴 | No security headers | Add `helmet` |
| 🟠 | No rate limiting | Add `express-rate-limit` |
| 🟠 | No error handler — stack traces may leak | Add global error-handling middleware |
| 🟠 | Hardcoded port | Use `process.env.PORT` |
| 🟡 | No CORS policy | Configure explicit origin allowlist |
| 🟡 | Timestamp in `/health` | Remove or restrict |
| 🟡 | No request logging | Add `morgan` or structured logger |
| 🔵 | No body size limits | Add `express.json({ limit: '10kb' })` |
| ℹ️ | No input validation framework | Adopt `zod`/`joi` before adding input-accepting routes |

---

## Quick-Win Consolidated Snippet

Here is a hardened version of the full file incorporating all the above:

```js
require('dotenv').config();
const express = require('express');
const helmet  = require('helmet');
const cors    = require('cors');
const morgan  = require('morgan');
const rateLimit = require('express-rate-limit');
const jwt     = require('jsonwebtoken');

const app = express();

// ── Security middleware ────────────────────────────────────────────
app.use(helmet());
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? [],
  methods: ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
app.use(morgan('combined'));
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100, standardHeaders: true }));

// ── Auth middleware ────────────────────────────────────────────────
const authenticateToken = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  jwt.verify(token, process.env.JWT_SECRET, (err, user) => {
    if (err) return res.status(403).json({ error: 'Forbidden' });
    req.user = user;
    next();
  });
};

// ── Routes ────────────────────────────────────────────────────────
app.get('/health', (req, res) => {
  res.json({ status: 'ok' });                  // removed timestamp
});

app.get('/users', authenticateToken, (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob',   email: 'bob@example.com'   },
  ]);
});

// ── Global error handler ──────────────────────────────────────────
app.use((err, req, res, _next) => {
  console.error({ path: req.path, message: err.message, stack: err.stack });
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'An unexpected error occurred.'
      : err.message,
  });
});

// ── Start ─────────────────────────────────────────────────────────
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));

module.exports = app;
```

Required additions to `package.json`:
```json
"dependencies": {
  "dotenv": "^16",
  "express": "^4",
  "express-rate-limit": "^7",
  "helmet": "^7",
  "cors": "^2",
  "morgan": "^1",
  "jsonwebtoken": "^9",
  "zod": "^3"
}
```

---

